489→    bottom: -4px;
490→    left: -4px;
491→    width: 12px;
492→    height: 12px;
493→    background-color: var(--bg-pill);
494→    border: 1px solid var(--editor-text);
495→    border-radius: 50%;
496→    cursor: nesw-resize;
497→    z-index: 10;
