530→    border: 1px solid var(--editor-text);
531→    border-radius: 2px;
532→    transform: translateY(-50%);
533→    cursor: ew-resize;
534→    z-index: 10;
535→}
536→.south-side-handle {
537→    position: absolute;
538→    bottom: -4px;
539→    left: 50%;
540→    width: 20px;
541→    height: 8px;
542→    background-color: var(--bg-pill);
543→    border: 1px solid var(--editor-text);
544→    border-radius: 2px;
545→    transform: translateX(-50%);
546→    cursor: ns-resize;
547→    z-index: 10;
548→}
549→.north-side-handle {
550→    position: absolute;
551→    top: -4px;
552→    left: 50%;
553→    width: 20px;
554→    height: 8px;
555→    background-color: var(--bg-pill);
556→    border: 1px solid var(--editor-text);
557→    border-radius: 2px;
558→    transform: translateX(-50%);
559→    cursor: nw-resize;
560→    z-index: 10;
561→}
