563→/* ── Image loading overlay ── */
564→.image-loading-overlay {
565→    position: absolute;
566→    top: 0;
567→    left: 0;
568→    width: 100%;
569→    height: 100%;
570→    display: flex;
571→    flex-direction: column;
572→    justify-content: center;
