 1→import { AnimatePresence, motion } from "framer-motion";
 2→import styles from "./PieMenu.module.css";
 3→
 4→const RADIUS = 72;
 5→
 6→const PieMenu = ({isOpen, position, items, onClose, isDark}) => {
 7→    if(!isOpen || !position || !items?.length){
 8→        return null;
 9→    }
10→
11→    const angleStep = (2 * Math.PI) / items.length;
12→    const startAngle = -Math.PI / 2;
13→
14→    return (
15→        <AnimatePresence>
16→            {isOpen && (
17→                <motion.div
18→                    className={`${styles.overlay} ${isDark ? styles.isDark : ""}`}
19→                    initial={{opacity: 0}}
20→                    animate={{opacity: 1}}
21→                    exit={{opacity: 0}}
22→                    transition={{duration: 0.15}}
23→                    onClick={onClose}
24→                    onContextMenu={(e) => {
25→                        e.preventDefault();
26→                        onClose();
27→                    }}
28→                >
29→                    <div
30→                        className={styles.ring}
31→                        style={{left: position.x, top: position.y}}
32→                    >
33→                        {items.map((item, index) => {
34→                            const angle = startAngle + index * angleStep;
35→                            const x = Math.cos(angle) * RADIUS;
36→                            const y = Math.sin(angle) * RADIUS;
37→
38→                            return (
39→                                <motion.button
40→                                    key={item.label}
41→                                    type="button"
42→                                    className={`${styles.item} ${item.isDelete ? styles.deleteItem : ""}`}
43→                                    style={{left: x, top: y}}
44→                                    initial={{scale: 0, opacity: 0}}
45→                                    animate={{scale: 1, opacity: 1}}
46→                                    exit={{scale: 0, opacity: 0}}
47→                                    transition={{
48→                                        type: "spring",
49→                                        stiffness: 420,
50→                                        damping: 22,
51→                                        delay: index * 0.03
52→                                    }}
53→                                    onClick={(e) => {
54→                                        e.stopPropagation();
55→                                        item.action();
56→                                        onClose();
57→                                    }}
58→                                    title={item.label}
59→                                >
60→                                    {item.icon || item.label}
61→                                </motion.button>
62→                            );
63→                        })}
64→                    </div>
65→                </motion.div>
66→            )}
67→        </AnimatePresence>
68→    );
69→};
70→
71→export default PieMenu;
